CREATE DATABASE IF NOT EXISTS educore; USE educore;
CREATE TABLE IF NOT EXISTS evaluation ( id INT PRIMARY KEY AUTO_INCREMENT, titre VARCHAR(150) NOT NULL, description TEXT, type ENUM('qcm','examen','devoir','projet','tp') DEFAULT 'qcm', duree_minutes INT, note_max FLOAT DEFAULT 20, note_passage FLOAT DEFAULT 10, nb_tentatives INT DEFAULT 1, ordre_aleatoire BOOLEAN DEFAULT FALSE, afficher_correc BOOLEAN DEFAULT TRUE, date_debut DATETIME, date_fin DATETIME, statut ENUM('brouillon','publie','ferme') DEFAULT 'brouillon', date_creation DATETIME DEFAULT NOW() );
CREATE TABLE IF NOT EXISTS question ( id INT PRIMARY KEY AUTO_INCREMENT, texte TEXT NOT NULL, type ENUM('qcm','vrai_faux','texte_libre','correspondance') DEFAULT 'qcm', points FLOAT DEFAULT 1, explication TEXT, image_url VARCHAR(255), ordre INT DEFAULT 0, evaluation_id INT NOT NULL, FOREIGN KEY (evaluation_id) REFERENCES evaluation(id) );
CREATE TABLE IF NOT EXISTS reponse ( id INT PRIMARY KEY AUTO_INCREMENT, texte TEXT NOT NULL, est_correct BOOLEAN DEFAULT FALSE, explication TEXT, ordre INT DEFAULT 0, question_id INT NOT NULL, FOREIGN KEY (question_id) REFERENCES question(id) );
CREATE TABLE IF NOT EXISTS reponse_etudiant ( id INT PRIMARY KEY AUTO_INCREMENT, resultat_id INT NOT NULL, question_id INT NOT NULL, reponse_id INT, texte_libre TEXT, est_correct BOOLEAN DEFAULT FALSE, points_obtenus FLOAT DEFAULT 0, FOREIGN KEY (resultat_id) REFERENCES resultat(id), FOREIGN KEY (question_id) REFERENCES question(id), FOREIGN KEY (reponse_id) REFERENCES reponse(id) );

CREATE DATABASE IF NOT EXISTS educore; USE educore;
CREATE TABLE IF NOT EXISTS evaluation ( id INT PRIMARY KEY AUTO_INCREMENT, titre VARCHAR(150) NOT NULL, description TEXT, type ENUM('qcm','examen','devoir','projet','tp') DEFAULT 'qcm', duree_minutes INT, note_max FLOAT DEFAULT 20, note_passage FLOAT DEFAULT 10, nb_tentatives INT DEFAULT 1, ordre_aleatoire BOOLEAN DEFAULT FALSE, afficher_correc BOOLEAN DEFAULT TRUE, date_debut DATETIME, date_fin DATETIME, statut ENUM('brouillon','publie','ferme') DEFAULT 'brouillon', date_creation DATETIME DEFAULT NOW() );
CREATE TABLE IF NOT EXISTS question ( id INT PRIMARY KEY AUTO_INCREMENT, texte TEXT NOT NULL, type ENUM('qcm','vrai_faux','texte_libre','correspondance') DEFAULT 'qcm', points FLOAT DEFAULT 1, explication TEXT, image_url VARCHAR(255), ordre INT DEFAULT 0, evaluation_id INT NOT NULL, FOREIGN KEY (evaluation_id) REFERENCES evaluation(id) );
CREATE TABLE IF NOT EXISTS reponse ( id INT PRIMARY KEY AUTO_INCREMENT, texte TEXT NOT NULL, est_correct BOOLEAN DEFAULT FALSE, explication TEXT, ordre INT DEFAULT 0, question_id INT NOT NULL, FOREIGN KEY (question_id) REFERENCES question(id) );
CREATE TABLE IF NOT EXISTS resultat ( id INT PRIMARY KEY AUTO_INCREMENT, score FLOAT NOT NULL, score_pourcentage FLOAT, est_reussi BOOLEAN DEFAULT FALSE, temps_passe_min INT, tentative_num INT DEFAULT 1, date_passage DATETIME DEFAULT NOW(), evaluation_id INT NOT NULL, FOREIGN KEY (evaluation_id) REFERENCES evaluation(id) );
CREATE TABLE IF NOT EXISTS reponse_etudiant ( id INT PRIMARY KEY AUTO_INCREMENT, resultat_id INT NOT NULL, question_id INT NOT NULL, reponse_id INT, texte_libre TEXT, est_correct BOOLEAN DEFAULT FALSE, points_obtenus FLOAT DEFAULT 0, FOREIGN KEY (resultat_id) REFERENCES resultat(id), FOREIGN KEY (question_id) REFERENCES question(id), FOREIGN KEY (reponse_id) REFERENCES reponse(id) );

package services;

import interfaces.IService;
import models.Resultat;
import utils.MyDataBase;

import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.sql.Statement;
import java.sql.Timestamp;
import java.util.ArrayList;
import java.util.List;

public class ResultatDAOImpl implements IService<Resultat> {

    @Override
    public void add(Resultat resultat) {
        String req = "INSERT INTO resultat (score, score_pourcentage, est_reussi, temps_passe_min, tentative_num, date_passage, evaluation_id) VALUES (?, ?, ?, ?, ?, ?, ?)";
        try (PreparedStatement ps = MyDataBase.getInstance().getConnection().prepareStatement(req)) {
            ps.setFloat(1, resultat.getScore());
            ps.setFloat(2, resultat.getScorePourcentage());
            ps.setBoolean(3, resultat.isEstReussi());
            ps.setInt(4, resultat.getTempsPasseMin());
            ps.setInt(5, resultat.getTentativeNum());
            ps.setTimestamp(6, Timestamp.valueOf(resultat.getDatePassage()));
            ps.setInt(7, resultat.getEvaluationId());
            ps.executeUpdate();
        } catch (SQLException e) {
            System.out.println(e.getMessage());
        }
    }

    @Override
    public void update(Resultat resultat) {
        String req = "UPDATE resultat SET score = ?, score_pourcentage = ?, est_reussi = ?, temps_passe_min = ?, tentative_num = ?, date_passage = ?, evaluation_id = ? WHERE id = ?";
        try (PreparedStatement ps = MyDataBase.getInstance().getConnection().prepareStatement(req)) {
            ps.setFloat(1, resultat.getScore());
            ps.setFloat(2, resultat.getScorePourcentage());
            ps.setBoolean(3, resultat.isEstReussi());
            ps.setInt(4, resultat.getTempsPasseMin());
            ps.setInt(5, resultat.getTentativeNum());
            ps.setTimestamp(6, Timestamp.valueOf(resultat.getDatePassage()));
            ps.setInt(7, resultat.getEvaluationId());
            ps.setInt(8, resultat.getId());
            ps.executeUpdate();
        } catch (SQLException e) {
            System.out.println(e.getMessage());
        }
    }

    @Override
    public void delete(int id) {
        String req = "DELETE FROM resultat WHERE id = ?";
        try (PreparedStatement ps = MyDataBase.getInstance().getConnection().prepareStatement(req)) {
            ps.setInt(1, id);
            ps.executeUpdate();
        } catch (SQLException e) {
            System.out.println(e.getMessage());
        }
    }

    @Override
    public Resultat getById(int id) {
        String req = "SELECT * FROM resultat WHERE id = ?";
        try (PreparedStatement ps = MyDataBase.getInstance().getConnection().prepareStatement(req)) {
            ps.setInt(1, id);
            try (ResultSet rs = ps.executeQuery()) {
                if (rs.next()) {
                    Resultat resultat = new Resultat();
                    resultat.setId(rs.getInt("id"));
                    resultat.setScore(rs.getFloat("score"));
                    resultat.setScorePourcentage(rs.getFloat("score_pourcentage"));
                    resultat.setEstReussi(rs.getBoolean("est_reussi"));
                    resultat.setTempsPasseMin(rs.getInt("temps_passe_min"));
                    resultat.setTentativeNum(rs.getInt("tentative_num"));
                    resultat.setDatePassage(rs.getTimestamp("date_passage").toLocalDateTime());
                    resultat.setEvaluationId(rs.getInt("evaluation_id"));
                    return resultat;
                }
            }
        } catch (SQLException e) {
            System.out.println(e.getMessage());
        }

        return null;
    }

    @Override
    public List<Resultat> getAll() {
        List<Resultat> resultats = new ArrayList<>();
        String req = "SELECT * FROM resultat";

        try (Statement stm = MyDataBase.getInstance().getConnection().createStatement();
             ResultSet rs = stm.executeQuery(req)) {

            while (rs.next()) {
                Resultat resultat = new Resultat();
                resultat.setId(rs.getInt("id"));
                resultat.setScore(rs.getFloat("score"));
                resultat.setScorePourcentage(rs.getFloat("score_pourcentage"));
                resultat.setEstReussi(rs.getBoolean("est_reussi"));
                resultat.setTempsPasseMin(rs.getInt("temps_passe_min"));
                resultat.setTentativeNum(rs.getInt("tentative_num"));
                resultat.setDatePassage(rs.getTimestamp("date_passage").toLocalDateTime());
                resultat.setEvaluationId(rs.getInt("evaluation_id"));
                resultats.add(resultat);
            }
        } catch (SQLException e) {
            System.out.println(e.getMessage());
        }

        return resultats;
    }
}
